import React, { useEffect, useState } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Divider,
  CircularProgress,
  FormControl,
  FormControlLabel,
  Checkbox,
  FormHelperText,
  InputAdornment,
  Stack,
  Alert
} from '@mui/material';
import { HexColorPicker } from 'react-colorful';
import { useFirebase } from '../../context/FirebaseContext';
import { Company } from '../../types';

interface CompanyFormProps {
  company?: Company;
  onCancel: () => void;
  onSaved: () => void;
}

interface FormValues {
  name: string;
  description: string;
  logo: string;
  website: string;
  email: string;
  phone: string;
  address: string;
  color: string;
  isMain: boolean;
}

interface FormErrors {
  name?: string;
  logo?: string;
  email?: string;
  website?: string;
}

const CompanyForm: React.FC<CompanyFormProps> = ({ company, onCancel, onSaved }) => {
  const { addCompany, editCompany } = useFirebase();
  
  const [formValues, setFormValues] = useState<FormValues>({
    name: '',
    description: '',
    logo: '',
    website: '',
    email: '',
    phone: '',
    address: '',
    color: '#0066cc',
    isMain: false
  });
  
  const [errors, setErrors] = useState<FormErrors>({});
  const [loading, setLoading] = useState(false);
  const [savedMessage, setSavedMessage] = useState<string | null>(null);
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [checkingLogo, setCheckingLogo] = useState(false);
  
  useEffect(() => {
    if (company) {
      setFormValues({
        name: company.name || '',
        description: company.description || '',
        logo: company.logo || '',
        website: company.website || '',
        email: company.email || '',
        phone: company.phone || '',
        address: company.address || '',
        color: company.color || '#0066cc',
        isMain: company.isMain || false
      });
      
      if (company.logo) {
        setLogoPreview(company.logo);
      }
    }
  }, [company]);
  
  const validateForm = (): boolean => {
    const newErrors: FormErrors = {};
    
    if (!formValues.name.trim()) {
      newErrors.name = 'ÐÐ°Ð·ÐēÐ°Ð―ÐļÐĩ ÐšÐūÐžÐŋÐ°Ð―ÐļÐļ ÐūÐąŅÐ·Ð°ŅÐĩÐŧŅÐ―Ðū';
    }
    
    if (!formValues.logo.trim()) {
      newErrors.logo = 'URL ÐŧÐūÐģÐūŅÐļÐŋÐ° ÐūÐąŅÐ·Ð°ŅÐĩÐŧÐĩÐ―';
    } else if (!/^https?:\/\/.+/.test(formValues.logo)) {
      newErrors.logo = 'URL ÐīÐūÐŧÐķÐĩÐ― Ð―Ð°ŅÐļÐ―Ð°ŅŅŅŅ Ņ http:// ÐļÐŧÐļ https://';
    }
    
    if (formValues.email && !/^\S+@\S+\.\S+$/.test(formValues.email)) {
      newErrors.email = 'ÐÐĩÐšÐūŅŅÐĩÐšŅÐ―ŅÐđ ŅÐūŅÐžÐ°Ņ ŅÐŧÐĩÐšŅŅÐūÐ―Ð―ÐūÐđ ÐŋÐūŅŅŅ';
    }
    
    if (formValues.website && !/^https?:\/\/\S+\.\S+/.test(formValues.website)) {
      newErrors.website = 'URL ÐīÐūÐŧÐķÐĩÐ― Ð―Ð°ŅÐļÐ―Ð°ŅŅŅŅ Ņ http:// ÐļÐŧÐļ https://';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };
  
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!validateForm()) {
      return;
    }
    
    setLoading(true);
    
    try {
      if (company) {
        // Update existing company
        await editCompany(company.id, {
          name: formValues.name,
          description: formValues.description || '',
          logo: formValues.logo,
          website: formValues.website || '',
          email: formValues.email || '',
          phone: formValues.phone || '',
          address: formValues.address || '',
          color: formValues.color,
          isMain: formValues.isMain
        });
        setSavedMessage('ÐÐūÐžÐŋÐ°Ð―ÐļŅ ŅŅÐŋÐĩŅÐ―Ðū ÐūÐąÐ―ÐūÐēÐŧÐĩÐ―Ð°');
      } else {
        // Add new company
        await addCompany({
          name: formValues.name,
          description: formValues.description || '',
          logo: formValues.logo,
          website: formValues.website || '',
          email: formValues.email || '',
          phone: formValues.phone || '',
          address: formValues.address || '',
          color: formValues.color,
          isMain: formValues.isMain,
          createdAt: new Date(),
          updatedAt: new Date()
        });
        setSavedMessage('ÐÐūÐžÐŋÐ°Ð―ÐļŅ ŅŅÐŋÐĩŅÐ―Ðū ÐīÐūÐąÐ°ÐēÐŧÐĩÐ―Ð°');
      }
      
      setTimeout(() => {
        onSaved();
      }, 1500);
      
    } catch (error) {
      console.error('Error saving company:', error);
      setSavedMessage('ÐŅÐļÐąÐšÐ° ÐŋŅÐļ ŅÐūŅŅÐ°Ð―ÐĩÐ―ÐļÐļ ÐšÐūÐžÐŋÐ°Ð―ÐļÐļ');
    } finally {
      setLoading(false);
    }
  };
  
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    
    setFormValues(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
    
    // Clear error for this field if it exists
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({
        ...prev,
        [name]: undefined
      }));
    }
  };
  
  const checkLogoUrl = async () => {
    if (!formValues.logo) {
      setLogoPreview(null);
      return;
    }
    
    setCheckingLogo(true);
    
    try {
      const response = await fetch(formValues.logo, { method: 'HEAD' });
      if (response.ok) {
        setLogoPreview(formValues.logo);
        setErrors(prev => ({ ...prev, logo: undefined }));
      } else {
        setLogoPreview(null);
        setErrors(prev => ({ ...prev, logo: 'ÐÐĩ ŅÐīÐ°ÐŧÐūŅŅ Ð·Ð°ÐģŅŅÐ·ÐļŅŅ ÐļÐ·ÐūÐąŅÐ°ÐķÐĩÐ―ÐļÐĩ' }));
      }
    } catch (error) {
      setLogoPreview(null);
      setErrors(prev => ({ ...prev, logo: 'ÐÐĩÐšÐūŅŅÐĩÐšŅÐ―ŅÐđ URL ÐļÐ·ÐūÐąŅÐ°ÐķÐĩÐ―ÐļŅ' }));
    } finally {
      setCheckingLogo(false);
    }
  };
  
  useEffect(() => {
    const debounce = setTimeout(() => {
      if (formValues.logo) {
        checkLogoUrl();
      }
    }, 500);
    
    return () => clearTimeout(debounce);
  }, [formValues.logo]);
  
  return (
    <Box component="form" onSubmit={handleSubmit} noValidate>
      <Typography variant="h6" gutterBottom>
        {company ? 'Ð ÐĩÐīÐ°ÐšŅÐļŅÐūÐēÐ°Ð―ÐļÐĩ ÐšÐūÐžÐŋÐ°Ð―ÐļÐļ' : 'ÐÐūÐąÐ°ÐēÐŧÐĩÐ―ÐļÐĩ Ð―ÐūÐēÐūÐđ ÐšÐūÐžÐŋÐ°Ð―ÐļÐļ'}
      </Typography>
      
      <Divider sx={{ mb: 3 }} />
      
      {savedMessage && (
        <Alert 
          severity={savedMessage.includes('ŅŅÐŋÐĩŅÐ―Ðū') ? 'success' : 'error'} 
          sx={{ mb: 3 }}
        >
          {savedMessage}
        </Alert>
      )}
      
      <Stack spacing={3}>
        <TextField
          fullWidth
          label="ÐÐ°Ð·ÐēÐ°Ð―ÐļÐĩ ÐšÐūÐžÐŋÐ°Ð―ÐļÐļ"
          name="name"
          value={formValues.name}
          onChange={handleChange}
          required
          error={!!errors.name}
          helperText={errors.name}
        />
        
        <TextField
          fullWidth
          label="ÐÐŋÐļŅÐ°Ð―ÐļÐĩ"
          name="description"
          value={formValues.description}
          onChange={handleChange}
          multiline
          rows={3}
        />
        
        <TextField
          fullWidth
          label="URL ÐŧÐūÐģÐūŅÐļÐŋÐ°"
          name="logo"
          value={formValues.logo}
          onChange={handleChange}
          required
          error={!!errors.logo}
          helperText={errors.logo}
          InputProps={{
            endAdornment: checkingLogo && (
              <InputAdornment position="end">
                <CircularProgress size={20} />
              </InputAdornment>
            )
          }}
        />
        
        {logoPreview && (
          <Box 
            sx={{ 
              textAlign: 'center', 
              p: 2, 
              border: '1px solid #ddd', 
              borderRadius: 1,
              backgroundColor: '#f9f9f9'
            }}
          >
            <Typography variant="subtitle2" gutterBottom>
              ÐŅÐĩÐīÐŋŅÐūŅÐžÐūŅŅ ÐŧÐūÐģÐūŅÐļÐŋÐ°
            </Typography>
            <Box
              component="img"
              src={logoPreview}
              alt="Logo preview"
              sx={{
                maxHeight: 100,
                maxWidth: '100%',
                objectFit: 'contain'
              }}
              onError={() => {
                setLogoPreview(null);
                setErrors(prev => ({ ...prev, logo: 'ÐÐĩ ŅÐīÐ°ÐŧÐūŅŅ Ð·Ð°ÐģŅŅÐ·ÐļŅŅ ÐļÐ·ÐūÐąŅÐ°ÐķÐĩÐ―ÐļÐĩ' }));
              }}
            />
          </Box>
        )}
        
        <Box>
          <Typography variant="subtitle2" gutterBottom>
            ÐĶÐēÐĩŅ ÐšÐūÐžÐŋÐ°Ð―ÐļÐļ
          </Typography>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
            <HexColorPicker 
              color={formValues.color}
              onChange={(color: string) => setFormValues(prev => ({ ...prev, color }))}
            />
            <Box>
              <TextField
                label="ÐĶÐēÐĩŅÐūÐēÐūÐđ ÐšÐūÐī"
                value={formValues.color}
                onChange={(e) => setFormValues(prev => ({ ...prev, color: e.target.value }))}
                size="small"
                sx={{ mb: 1 }}
              />
              <Box 
                sx={{ 
                  width: 40, 
                  height: 40, 
                  bgcolor: formValues.color,
                  borderRadius: 1,
                  border: '1px solid #ddd'
                }} 
              />
            </Box>
          </Box>
        </Box>
        
        <Divider />
        
        <Typography variant="subtitle1">
          ÐÐūÐ―ŅÐ°ÐšŅÐ―Ð°Ņ ÐļÐ―ŅÐūŅÐžÐ°ŅÐļŅ
        </Typography>
        
        <TextField
          fullWidth
          label="ÐÐĩÐą-ŅÐ°ÐđŅ"
          name="website"
          value={formValues.website}
          onChange={handleChange}
          error={!!errors.website}
          helperText={errors.website}
          placeholder="https://example.com"
        />
        
        <TextField
          fullWidth
          label="Email"
          name="email"
          type="email"
          value={formValues.email}
          onChange={handleChange}
          error={!!errors.email}
          helperText={errors.email}
        />
        
        <TextField
          fullWidth
          label="ÐĒÐĩÐŧÐĩŅÐūÐ―"
          name="phone"
          value={formValues.phone}
          onChange={handleChange}
        />
        
        <TextField
          fullWidth
          label="ÐÐīŅÐĩŅ"
          name="address"
          value={formValues.address}
          onChange={handleChange}
        />
        
        <FormControl>
          <FormControlLabel
            control={
              <Checkbox
                checked={formValues.isMain}
                onChange={handleChange}
                name="isMain"
              />
            }
            label="ÐŅÐ―ÐūÐēÐ―Ð°Ņ ÐšÐūÐžÐŋÐ°Ð―ÐļŅ"
          />
          <FormHelperText>
            ÐŅÐžÐĩŅŅŅÐĩ, ÐĩŅÐŧÐļ ŅŅÐū ÐūŅÐ―ÐūÐēÐ―Ð°Ņ ÐšÐūÐžÐŋÐ°Ð―ÐļŅ. ÐŅÐ―ÐūÐēÐ―Ð°Ņ ÐšÐūÐžÐŋÐ°Ð―ÐļŅ ÐžÐūÐķÐĩŅ ÐąŅŅŅ ŅÐūÐŧŅÐšÐū ÐūÐīÐ―Ð°.
          </FormHelperText>
        </FormControl>
        
        <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end', gap: 2 }}>
          <Button onClick={onCancel} disabled={loading}>
            ÐŅÐžÐĩÐ―Ð°
          </Button>
          <Button 
            type="submit"
            variant="contained"
            disabled={loading}
            startIcon={loading && <CircularProgress size={20} color="inherit" />}
          >
            {company ? 'ÐĄÐūŅŅÐ°Ð―ÐļŅŅ' : 'ÐÐūÐąÐ°ÐēÐļŅŅ'}
          </Button>
        </Box>
      </Stack>
    </Box>
  );
};

export default CompanyForm;
